// Deterministic core of ce-verify-work: a plan-unit parser and a verdict roll-up.
//
// Pure module: no Workflow/Agent/filesystem dependencies. It is importable by
// `bun test` AND designed to be inlined into the dynamic workflow script (the
// Workflow runtime is self-contained and cannot `import` a sibling file, so
// work-vs-plan-fanout.js prepends this module's function bodies; the single
// trailing `export` line is the only thing that must be stripped on inline).
// The orchestrator's pre-dispatch validation and the prose fallback both reuse
// parsePlanUnits / rollupVerdicts, so the rate cannot diverge across paths.
//
// Faithful to:
//   plugins/compound-engineering/skills/ce-plan/SKILL.md  (### U<n>. unit spec)
//   plugins/compound-engineering/skills/ce-verify-work/references/verdict-schema.json
//
// Key Decision 4: drift_rate = drifted / (done + drifted). `remaining` (never
// attempted) and `unverifiable` (not statically settleable) are counted but
// EXCLUDED from the denominator, so the rate measures the redo-shaped subset,
// not how far along the plan is.

const VALID_VERDICTS = new Set(["done", "remaining", "drifted", "unverifiable"]);
// Verdicts whose claim must be provable — an uncited done/drifted is dropped,
// so the rate is recomputed from cited verdicts only (Key Decision 5).
const EVIDENCE_REQUIRED = new Set(["done", "drifted"]);
// Below this many attempted (done + drifted) units the denominator is too small
// to trust — a 1-done/1-drifted plan reads 0.5 from a meaningless sample.
const ATTEMPTED_FLOOR = 3;
// A run dominated by unverifiable units is low-confidence even if a few units
// were attempted — the rate covers too little of the plan.
const UNVERIFIABLE_FRACTION = 0.5;

const FIELD_NAMES = {
  goal: "goal",
  requirements: "requirements",
  dependencies: "dependencies",
  files: "files",
  approach: "approach",
  "execution note": "execution_note",
  "patterns to follow": "patterns",
  "test scenarios": "test_scenarios",
  verification: "verification",
};

// ---- plan parsing ----------------------------------------------------------

// ce-work reads both markdown and HTML plans. HTML plans carry the same section
// and field names, just wrapped in semantic elements (<h3>U1. ...</h3>,
// <dt>Goal</dt><dd>...</dd>, <details><summary>Verification</summary>...). Fold
// the structural tags back to their markdown equivalents so one parser handles
// both; the U-ID is found as the literal "U1." text in either form.
function htmlToText(s) {
  return s
    .replace(/<h2[^>]*>/gi, "\n## ")
    .replace(/<\/h2>/gi, "\n")
    .replace(/<h[34][^>]*>/gi, "\n### ")
    .replace(/<\/h[34]>/gi, "\n")
    .replace(/<dt[^>]*>/gi, "\n**")
    .replace(/<\/dt>/gi, ":**")
    .replace(/<summary[^>]*>/gi, "\n**")
    .replace(/<\/summary>/gi, ":**")
    .replace(/<(strong|b)[^>]*>/gi, "**")
    .replace(/<\/(strong|b)>/gi, "**")
    .replace(/<code[^>]*>/gi, "`")
    .replace(/<\/code>/gi, "`")
    .replace(/<li[^>]*>/gi, "\n- ")
    .replace(/<\/li>/gi, "\n")
    .replace(/<\/(p|dd|dl|ul|ol|article|section|details|div)>/gi, "\n")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");
}

function looksLikeHtml(s) {
  return /<(h[1-6]|article|section|dl|dt|details)\b/i.test(s);
}

// Drop legacy `- [ ]` / `- [x]` checkbox marks from a heading. ce-plan forbids
// them, but legacy plans carry them; they are never read as done/remaining state.
function stripCheckbox(s) {
  return s.replace(/\[[ xX]\]/g, "").replace(/\s+/g, " ").trim();
}

function isTestPath(p) {
  return /(^|\/)tests?\//.test(p) || /[._-](test|spec)\.[A-Za-z0-9]+$/i.test(p);
}

// Well-known extensionless repo files. A bare token (no slash, no extension)
// is a real path only when it is one of these — this readmits `Dockerfile` /
// `Makefile` / `LICENSE` without also readmitting bare identifiers like
// `import` / `fs` / `Read` that appear in Files prose. (Dotfiles such as
// `.gitignore` already pass via the extension rule — the leading dot reads as
// `.ext`.) Heuristic, not exhaustive: an obscure extensionless file not listed
// here is still dropped, which is acceptable for a Files-block scanner.
const EXTENSIONLESS_FILES = new Set([
  "dockerfile", "makefile", "license", "procfile", "gemfile", "rakefile",
  "jenkinsfile", "brewfile", "vagrantfile", "caddyfile", "justfile", "containerfile",
  "notice", "authors", "contributors", "codeowners", "readme", "changelog", "version",
]);

// A backtick span inside a Files block is a real declared path only if it has a
// path shape. Files prose mixes inline code that is NOT a path — globs (`ce-*`),
// templated placeholders (`ce-<name>.md`), shell commands (`bun run release:validate`),
// and bare identifiers (`import`, `fs`). Skip those so they never read as a
// missing/declared file. A path has no whitespace, no glob/placeholder chars,
// and either a directory separator, a trailing file extension, or a known
// extensionless filename.
function isPlausiblePath(p) {
  if (/\s/.test(p)) return false;
  if (/[*<>]/.test(p)) return false;
  if (p.includes("/") || /\.[A-Za-z0-9]+$/.test(p)) return true;
  return EXTENSIONLESS_FILES.has(p.toLowerCase());
}

// From a Files field block, pull each backtick-wrapped path and classify it by
// its trailing annotation (`(new)` -> create, `(modified)`/`(extended)` ->
// modify) and by path shape (test). `all` is every distinct declared path —
// the attempt signal the classifier checks against git is "a commit touched one
// of these".
function parseFiles(block) {
  const create = [];
  const modify = [];
  const test = [];
  const all = [];
  const seen = new Set();
  // Trailing capture stops at the next backtick (not end of line) so a Files
  // bullet with several backtick spans yields every token, not just the first.
  const re = /`([^`]+)`([^`\n]*)/g;
  let m;
  while ((m = re.exec(block))) {
    const p = m[1].trim();
    if (!p || !isPlausiblePath(p)) continue;
    const trailing = (m[2] || "").toLowerCase();
    if (!seen.has(p)) {
      seen.add(p);
      all.push(p);
      if (/\bnew\b/.test(trailing)) create.push(p);
      if (/modif|extend/.test(trailing)) modify.push(p);
      if (isTestPath(p)) test.push(p);
    }
  }
  return { create, modify, test, all };
}

/**
 * Parse a plan document (markdown or HTML) into its Implementation Units,
 * preserving each U-ID verbatim (gaps allowed; never renumbered). Returns an
 * empty array for input with no `### U<n>.` unit headings (which drives the
 * orchestrator's invalid_input). Pure: no fs, no network.
 */
function parsePlanUnits(planText) {
  if (typeof planText !== "string" || planText.length === 0) return [];
  const text = looksLikeHtml(planText) ? htmlToText(planText) : planText;
  const lines = text.split("\n");

  // Locate unit headings: a level-2..4 heading whose text (after checkbox strip)
  // is `U<n>. <name>`. Prose mentions of "U1" are not headings and are ignored.
  const heads = [];
  for (let i = 0; i < lines.length; i++) {
    const h = /^#{2,4}\s+(.*)$/.exec(lines[i]);
    if (!h) continue;
    const htext = stripCheckbox(h[1]);
    const u = /^(U\d+)\.\s*(.*)$/.exec(htext);
    if (u) heads.push({ line: i, u_id: u[1], name: u[2].trim() });
  }
  if (heads.length === 0) return [];

  // A unit body runs from its heading to the next unit heading, the next
  // level-2 section, or a horizontal rule — whichever comes first.
  function bodyEnd(start, nextHead) {
    for (let i = start; i < lines.length; i++) {
      if (i === nextHead) return i;
      if (/^##\s/.test(lines[i]) || /^---\s*$/.test(lines[i])) return i;
    }
    return lines.length;
  }

  return heads.map((head, idx) => {
    const nextHead = idx + 1 < heads.length ? heads[idx + 1].line : -1;
    const end = bodyEnd(head.line + 1, nextHead);
    const body = lines.slice(head.line + 1, end);
    const fields = parseFields(body);
    return {
      u_id: head.u_id,
      name: head.name,
      goal: fields.goal || "",
      requirements: fields.requirements || "",
      dependencies: fields.dependencies || "",
      files: parseFiles(fields.files || ""),
      approach: fields.approach || "",
      execution_note: fields.execution_note || "",
      patterns: fields.patterns || "",
      test_scenarios: fields.test_scenarios || "",
      verification: fields.verification || "",
    };
  });
}

// Split a unit body into its bold fields. A field starts at a `**Name:**` line;
// its value is the inline remainder plus every following line up to the next
// `**Name:**` start. Unknown field names are ignored.
function parseFields(bodyLines) {
  const out = {};
  let key = null;
  let buf = [];
  const flush = () => {
    if (key) out[key] = buf.join("\n").trim();
    buf = [];
  };
  for (const line of bodyLines) {
    const f = /^\s*\*\*([A-Za-z][A-Za-z /]*?):\*\*\s?(.*)$/.exec(line);
    if (f) {
      const mapped = FIELD_NAMES[f[1].trim().toLowerCase()];
      flush();
      if (mapped) {
        key = mapped;
        buf = [f[2]];
      } else {
        key = null;
      }
    } else if (key) {
      buf.push(line);
    }
  }
  flush();
  return out;
}

// ---- verdict roll-up -------------------------------------------------------

// Numeric order of a unit's U-id ("U3" -> 3), used to sort the roll-up output
// into the plan's unit order. A non-numeric id sorts last; the comparator
// breaks ties by u_id string so the order is total and deterministic.
function unitOrder(u_id) {
  const n = parseInt(u_id.slice(1), 10);
  return Number.isNaN(n) ? Number.POSITIVE_INFINITY : n;
}

/**
 * Roll an array of `{ u_id, verdict, evidence?, rationale? }` up into the drift
 * rate, verdict counts, ordered verdict table, and the low-confidence flag.
 * Malformed entries (bad verdict, missing u_id, or an uncited done/drifted) are
 * dropped and counted. Deterministic: same input -> byte-identical output, and
 * output is sorted by U-number so it does not depend on input order.
 */
function rollupVerdicts(verdicts) {
  const counts = { done: 0, remaining: 0, drifted: 0, unverifiable: 0, attempted: 0, dropped: 0 };
  const units = [];

  for (const raw of Array.isArray(verdicts) ? verdicts : []) {
    if (
      !raw ||
      typeof raw.u_id !== "string" ||
      raw.u_id.length === 0 ||
      !VALID_VERDICTS.has(raw.verdict)
    ) {
      counts.dropped++;
      continue;
    }
    const evidence = Array.isArray(raw.evidence) ? raw.evidence.filter((e) => typeof e === "string" && e.length > 0) : [];
    if (EVIDENCE_REQUIRED.has(raw.verdict) && evidence.length === 0) {
      counts.dropped++;
      continue;
    }
    const rationale = typeof raw.rationale === "string" ? raw.rationale : "";
    counts[raw.verdict]++;
    units.push({ u_id: raw.u_id, verdict: raw.verdict, evidence, rationale });
  }

  // Order by U-number (the plan's unit order), so output does NOT depend on the
  // model's verdict-emission order on the workflow path — a batch classifier may
  // return verdicts out of order. This keeps the committed drift-event artifact
  // byte-stable across runs of the same plan.
  units.sort((a, b) => unitOrder(a.u_id) - unitOrder(b.u_id) || (a.u_id < b.u_id ? -1 : a.u_id > b.u_id ? 1 : 0));

  const unverifiable = units
    .filter((u) => u.verdict === "unverifiable")
    .map((u) => ({ u_id: u.u_id, reason: u.rationale }));

  // Verdict-grouped unit-ID lists derived from the ordered units. The drift-event
  // capture (ce-verify-work Phase 4) copies these VERBATIM into the artifact's
  // data block, so an LLM never buckets a unit — the determinism is real at the
  // source. `attempted` = done + drifted (the rate's denominator); `drifted` is
  // its numerator. IDs only, never a rate (ADR 0001: derived from
  // |drifted| / |attempted| at read time).
  const grouped = {
    drifted: units.filter((u) => u.verdict === "drifted").map((u) => u.u_id),
    attempted: units.filter((u) => u.verdict === "done" || u.verdict === "drifted").map((u) => u.u_id),
    remaining: units.filter((u) => u.verdict === "remaining").map((u) => u.u_id),
    unverifiable: units.filter((u) => u.verdict === "unverifiable").map((u) => u.u_id),
  };

  counts.attempted = counts.done + counts.drifted;
  const total = counts.done + counts.remaining + counts.drifted + counts.unverifiable;
  const drift_rate = counts.attempted === 0 ? null : counts.drifted / counts.attempted;
  // Low-information sample: too few attempted units — INCLUDING zero, where an
  // all-remaining plan is the least-informative sample of all — or a run
  // dominated by unverifiable units. Guarded by `total > 0` so a genuinely empty
  // result (no valid verdicts) is not flagged.
  const low_confidence =
    total > 0 &&
    (counts.attempted < ATTEMPTED_FLOOR || counts.unverifiable / total >= UNVERIFIABLE_FRACTION);

  return { drift_rate, low_confidence, counts, units, unverifiable, grouped };
}


// Assembly inserts drift-rollup.js here, exposing parsePlanUnits(planText) and
// rollupVerdicts(verdicts).

// ---- args ------------------------------------------------------------------
// The Workflow runtime may deliver `args` as an object OR a JSON string. Parse
// defensively — a naive `args || {}` keeps the raw string, so every A.field is
// undefined and the workflow silently runs empty. A parse failure falls through
// to the input-contract guard below, which rejects it as invalid_input.
let A = args;
if (typeof A === "string") {
  try {
    A = JSON.parse(A);
  } catch (e) {
    log("args was a non-JSON string; treating as empty — the input-contract guard will reject it as invalid_input: " + (e && e.message ? e.message : String(e)));
    A = {};
  }
}
A = A || {};

// Input-contract guard (ADR 0002): a malformed CALL short-circuits with
// status:"invalid_input" BEFORE any agent dispatch — distinct from a degraded
// RUN, so a machine caller can tell "I mis-wired the call" from "the classifier
// had trouble." Structural defense-in-depth; the orchestrator validates fully
// (with fs) before ever invoking the workflow.
function validateArgs(a) {
  if (!a || typeof a !== "object") return { ok: false, error: "args missing or not an object" };
  if (typeof a.run_id !== "string" || !/^[A-Za-z0-9_-]+$/.test(a.run_id)) {
    return { ok: false, error: "run_id missing or not a path-safe [A-Za-z0-9_-]+ token" };
  }
  if (typeof a.plan_path !== "string" || !a.plan_path.startsWith("/")) {
    return { ok: false, error: "plan_path missing or not an absolute path" };
  }
  if (typeof a.plan_text !== "string" || a.plan_text.length === 0) {
    return { ok: false, error: "plan_text missing (the runtime has no fs; the orchestrator must pass the plan contents)" };
  }
  let batch_size = 6;
  if (a.batch_size != null) {
    const n = Number(a.batch_size);
    if (!Number.isInteger(n) || n < 1) return { ok: false, error: "batch_size must be a positive integer" };
    batch_size = n;
  }
  let agent_type;
  if (a.agentType != null) {
    // Require a real plugin-namespaced id: non-empty segments on both sides of a
    // single colon. A bare ":" or "foo:" is not meaningfully namespaced and
    // would fail to resolve at dispatch, so reject it here rather than swallow it.
    if (typeof a.agentType !== "string" || !/^[\w.-]+:[\w.-]+$/.test(a.agentType)) {
      return { ok: false, error: "agentType, when set, must be plugin-namespaced (e.g. compound-engineering:ce-...)" };
    }
    agent_type = a.agentType;
  }
  return { ok: true, normalized: { run_id: a.run_id, plan_path: a.plan_path, plan_text: a.plan_text, batch_size, agent_type } };
}

// Renderer-safe envelope for a contract violation: mirrors the success
// envelope's shape AND field types (empty collections, null rate) so a caller
// that reads fields does not crash; status + error carry the violation.
function invalidInputEnvelope(error) {
  return {
    status: "invalid_input",
    error,
    drift_rate: null,
    low_confidence: false,
    counts: { done: 0, remaining: 0, drifted: 0, unverifiable: 0, attempted: 0, dropped: 0, failed_batches: 0, total_units: 0 },
    units: [],
    unverifiable: [],
    plan_path: typeof A.plan_path === "string" ? A.plan_path : "",
    artifact_path: "",
    run_id: typeof A.run_id === "string" ? A.run_id : "",
  };
}

const VALIDATION = validateArgs(A);
if (!VALIDATION.ok) {
  log("invalid_input: " + VALIDATION.error);
  return invalidInputEnvelope(VALIDATION.error);
}
const RUN_ID = VALIDATION.normalized.run_id;
const PLAN_PATH = VALIDATION.normalized.plan_path;
const PLAN_TEXT = VALIDATION.normalized.plan_text;
const BATCH_SIZE = VALIDATION.normalized.batch_size;
const AGENT_TYPE = VALIDATION.normalized.agent_type;
const ARTIFACT_DIR = "/tmp/compound-engineering/ce-verify-work/" + RUN_ID;

// Per-batch classifier output: one verdict object per unit. Kept intentionally
// minimal (no conditional `if/then` for evidence) so it dispatches on any
// structured-output layer — the live smoke proved this shape works, and a
// conditional keyword the runtime might reject would risk the silent-empty
// failure mode. The done/drifted "must cite evidence" rule is carried in the
// rubric/prompt and ENFORCED deterministically by rollupVerdicts (it drops an
// uncited done/drifted and the drop count is logged below). The full conditional
// contract lives in references/verdict-schema.json for the prose fallback + docs.
const VERDICT_SCHEMA = {
  type: "object",
  required: ["verdicts"],
  properties: {
    verdicts: {
      type: "array",
      items: {
        type: "object",
        required: ["u_id", "verdict", "rationale"],
        properties: {
          u_id: { type: "string" },
          verdict: { type: "string", enum: ["done", "remaining", "drifted", "unverifiable"] },
          evidence: { type: "array", items: { type: "string" } },
          rationale: { type: "string" },
        },
      },
    },
  },
};

// Concise classifier rubric — the canonical full version is
// references/verdict-rubric.md (which the prose fallback loads). Inlined here
// because the workflow runtime cannot Read sibling files.
const RUBRIC = [
  "Verdicts (classify each unit against ACTUAL repo state — git + file state only):",
  "- done: declared Files present AND Verification satisfied by current repo state. REQUIRES non-empty evidence (cite existing paths, landing commits, the satisfying code/test).",
  "- remaining: NO git evidence the unit was attempted (no commit touched its declared paths). Progress, not rework — excluded from the drift rate. Inferred from absence of an attempt, never from 'not recently touched'.",
  "- drifted: a commit DID touch the declared paths BUT the repo diverged (Verification unmet, Files partial/deleted). Rework-shaped. REQUIRES non-empty evidence citing BOTH the attempt and the divergence.",
  "- unverifiable: HIGHEST BAR — Verification is intrinsically behavioral/runtime (e.g. 'improves latency') and cannot be settled from static repo state. A unit with concrete Files and a statically-checkable Verification is NEVER unverifiable.",
  "Rules: never read legacy [ ]/[x] checkbox marks as state. On a borderline statically-checkable call, lean drifted over a false done; never escape a checkable unit to unverifiable. When a touched path is shared across units, adjudicate by the unit's own Verification.",
].join("\n");

function unitBlock(u) {
  return [
    "### " + u.u_id + ". " + u.name,
    "Goal: " + (u.goal || "(none)"),
    "Declared files: " + (u.files && u.files.all.length ? u.files.all.join(", ") : "(none declared)"),
    "Verification: " + (u.verification || "(none stated)"),
  ].join("\n");
}

function batchPrompt(units) {
  return [
    "Classify each Implementation Unit below against the ACTUAL state of this git repository.",
    "Read the full plan for each unit's complete Goal/Approach/Verification: " + PLAN_PATH,
    "",
    RUBRIC,
    "",
    "Inspect repo state with native file tools (Read/Grep/Glob) and single, unchained git commands run one at a time:",
    "  - do the declared file paths exist, and with the claimed capability? (Read/Glob)",
    "  - did any commit touch a declared path? (git log --oneline -- <path>) and what changed? (git log -p -- <path>)",
    "  - is the Verification satisfied by what is actually present?",
    "Treat 'file absent' / 'no such ref' as DATA (a remaining or drifted signal), never an aborting error.",
    "",
    "Units to classify in this batch:",
    "",
    units.map(unitBlock).join("\n\n"),
    "",
    "Return ONE verdict object per unit, u_id verbatim. done and drifted REQUIRE a non-empty evidence array (repo-relative paths, commit SHAs, diff-hunk references). Keep rationale to one sentence.",
  ].join("\n");
}

function chunk(arr, size) {
  const out = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out;
}

// ---- classify --------------------------------------------------------------
phase("Classify");

const UNITS = parsePlanUnits(PLAN_TEXT);
if (UNITS.length === 0) {
  // The orchestrator should have caught this; defend the boundary anyway.
  return invalidInputEnvelope("plan_text parsed to zero Implementation Units");
}

const batches = chunk(UNITS, BATCH_SIZE);
const results = await parallel(
  batches.map((batch, i) => () =>
    agent(batchPrompt(batch), {
      label: "classify:batch-" + (i + 1),
      phase: "Classify",
      schema: VERDICT_SCHEMA,
      ...(AGENT_TYPE ? { agentType: AGENT_TYPE } : {}),
    })
      .then((r) => {
        if (r && Array.isArray(r.verdicts)) return { ok: true, verdicts: r.verdicts };
        log("classify batch " + (i + 1) + " returned no verdicts");
        return { ok: false, verdicts: [] };
      })
      .catch((e) => {
        // Surface dispatch/runtime failures — a swallowed agentType-resolution
        // error reads as an empty, confidently-wrong drift rate.
        log("classify batch " + (i + 1) + " failed: " + (e && e.message ? e.message : String(e)));
        return { ok: false, verdicts: [] };
      }),
  ),
);

// ---- roll-up ---------------------------------------------------------------
phase("Roll-up");

const failedBatches = results.filter((r) => !r.ok).length;
const allVerdicts = results.flatMap((r) => r.verdicts);
const rolled = rollupVerdicts(allVerdicts);
const status = failedBatches > 0 ? "degraded" : "complete";

log(
  "Classified " + UNITS.length + " units in " + batches.length + " batches" +
    (failedBatches ? " (" + failedBatches + " failed)" : "") +
    (rolled.counts.dropped ? " (" + rolled.counts.dropped + " verdicts dropped — malformed or uncited)" : "") +
    "; drift_rate " + (rolled.drift_rate == null ? "n/a" : rolled.drift_rate.toFixed(2)) +
    (rolled.low_confidence ? " [low_confidence]" : ""),
);

return {
  status,
  drift_rate: rolled.drift_rate,
  low_confidence: rolled.low_confidence,
  counts: { ...rolled.counts, failed_batches: failedBatches, total_units: UNITS.length },
  units: rolled.units,
  unverifiable: rolled.unverifiable,
  // Verdict-grouped unit-ID lists for the drift-event capture (Phase 4) to copy
  // verbatim — the determinism lives in rollupVerdicts, not in an LLM re-group.
  grouped: rolled.grouped,
  plan_path: PLAN_PATH,
  artifact_path: ARTIFACT_DIR + "/",
  run_id: RUN_ID,
};
